insert into versions (id, project_id, seq, label, status, note, author_name, snapshot, created_by, created_at)
select gen_random_uuid(), (select pid from _fb), 1, '1.1', 'approved',
  'Baseline Father Profile Assessment, Phase 1 (FC-REQ-001).', 'Micah Canfield',
  '{"answers":{"ctrl_product":"Fathering Baseline Assessment","ctrl_org":"National Center for Fathering","ctrl_owner":"Micah Canfield","ctrl_status":"Approved","ov_purpose":"This document specifies the requirements for the Fathers.com Platform. Its first phase delivers the Baseline Father Profile Assessment, the validated self-report instrument that gives a father an objective starting point and a plan. It is the single source of truth for what Phase 1 must do and how acceptance is judged. Its audience is the product owner, the engineering team, the data and privacy reviewer, and the sponsor at the National Center for Fathering, together with the review and traceability process managed in ReqPub. Part I states the product without implementation detail; Part II states the requirements, each with a measurable fit criterion.","ov_vision":"Fathers.com equips any father to become measurably more present. It replaces vague encouragement with a validated baseline, a clear growth focus, and a personalized ninety-day plan, delivered at no cost by a nonprofit and available on any phone. Over time the platform extends into classes, certificates, peer circles, and programs for specific fathers, but the baseline is the front door: the moment a man learns where he actually stands and what to do next.","ov_problem":"Father absence and disengagement carry well-documented costs to children, and most fathers who want to do better have no objective, non-judgmental way to know where they stand or what specifically to change. Advice is generic, self-assessment is guesswork, and formal instruments are locked inside clinical or academic settings. The Baseline Father Profile Assessment closes that gap by giving any father a private, validated read on four dimensions of engaged fatherhood and a concrete plan built from his own result. It matters now because the instrument exists, the delivery platform is built, and the reach of a nonprofit with established distribution makes scale realistic.","ov_market":"The addressable population is the tens of millions of fathers of minor children in the United States, reached both directly and through the National Center for Fathering’s existing channels: faith communities, employers, fatherhood programs, and public agencies. The instrument’s value as an objective, court-neutral baseline also opens referral channels where an accountable, verifiable starting point is useful. Phase 1 targets the direct-to-father and partnered-group segments, where friction is lowest and the baseline stands on its own.","context":"The assessment runs in a web browser on a phone, tablet, or desktop, with no app install. Fathers frequently take it on a personal phone over a mobile connection, in a single sitting or across a short break, so the flow must be responsive, resumable, and tolerant of intermittent connectivity. Because the content is personal and self-reflective, the setting is assumed private to the father, and the platform never exposes one father’s data to another.","sol_solution":"The Baseline Father Profile Assessment is the delivery of the Keystone Father Profile: a validated self-report instrument that measures four domains of engaged fatherhood, Involvement, Consistency, Awareness, and Nurturance. A father answers a fixed set of items on a defined response scale. A deterministic scoring engine converts those responses into a score for each domain on a common 0 to 100 scale, a single overall baseline, the father’s strongest domain, and his growth focus, which is the domain with the largest opportunity to improve. From the growth focus the platform generates a ninety-day plan. The result and plan are private to the father. The core of the product is a measurement, not a generative guess: scoring is a fixed function of the responses and a versioned scoring model, so the same responses under the same model always produce the same result, which is what makes a baseline defensible. The model is architected as configuration plus a pure scoring function, kept strictly separate: the item bank, domains, scales, key directions, optional weights, normalization parameters, growth-focus rule, and plan mapping are one versioned configuration object that changes scoring with no code deployment and a full audit record; scoring is a pure function of (responses, model version); and every stored result carries the item-bank and model versions used, so a result computed a year ago can still be explained, recomputed, and defended.","staged":"Yes","has_ai":"Yes","golden":"The golden dataset pairs computed results with the facts a correct summary must and must not state, curated from vetted sources. An automated harness runs each candidate build against it and reports grounding, accuracy, latency, and guardrail metrics; a build below any EVAL threshold does not ship. A red-team set probes for hallucination, unsafe handling of distress, and sycophancy, with human review before and after release. This method applies to any release that introduces a generative result summary (FR-027); Phase 1 scoring itself is deterministic and verified by test against labeled fixtures, not by evaluation.","vulnerable":"Yes","safeguard":"If a father’s responses meet a defined distress signal (to confirm), the system surfaces a non-clinical support resource without blocking the father and without diagnosing; no diagnostic language appears. The response is verified by demonstration and red-team review, and reviewed by a clinical or policy owner. The product makes no clinical diagnosis, label, or treatment recommendation anywhere.","consent":"The platform obtains and records informed consent, with a timestamp, before it collects any assessment response; no response is stored without it. Individual results are never sold or shared with any third party; sharing an individual result to a referring organization requires a separate, explicitly specified consent flow that is out of scope for Phase 1.","retention":"A father can delete his assessment data at any time; on confirmed request his responses, results, and plan are removed and the removal is confirmed. Retention beyond deletion follows a stated policy (to confirm). A father can retake the assessment, producing a new dated result without overwriting prior ones, and can view his result history.","residency":"Assessment data is classified and handled as sensitive personal data. Personal data is encrypted in transit (TLS) and at rest. Data is stored in the region defined by the residency requirement (to confirm).","access":"A father’s responses, scores, and plan are private to his account and readable only by it; per-father isolation is enforced by row-level security at the database, not only the interface, so cross-account reads are denied even on direct database access. Administrators see only aggregate participation and score distributions, never an individual father’s answers or scores; any authorized access to individual data is logged. The platform does not knowingly process the data of minors.","verify_note":"Every requirement carries a fit criterion. Deterministic requirements are verified by test, inspection, or demonstration. Probabilistic or AI components are verified by evaluation against a golden dataset with the stated threshold. Safety requirements are verified on a red-team or scenario set with human review. Phase 1 is accepted when every Must requirement passes its fit criterion and every applicable evaluation criterion meets its threshold.","link_repo":"to confirm","link_board":"to confirm","link_design":"FORGE design system, on the production platform","ctrl_approvers":[{"role":"Product","name":"Micah Canfield","_k":1},{"role":"Engineering","name":"Alon Arad","_k":2},{"role":"Data and Privacy","name":"to confirm","_k":3},{"role":"Sponsor","name":"Dr. Ken Canfield","_k":4}],"ov_goals":["G1. Give a father a valid, private baseline across the four fatherhood domains in a single sitting of about twenty minutes.","G2. Translate every baseline into a concrete ninety-day plan mapped to the father’s largest growth opportunity.","G3. Protect the father’s data absolutely: private to his account, never sold, his to delete.","G4. Deliver the assessment reliably on a phone with no app install and minimal friction.","G5. Make scoring reproducible and auditable, so a result can be explained and defended under scrutiny."],"seg":[{"segment":"Individual fathers","share":"Primary","desc":"A father seeking an honest read on his fathering and a plan to improve.","_k":1},{"segment":"Partnered groups","share":"High","desc":"Churches, teams, and fatherhood programs that run the baseline with their men.","_k":2},{"segment":"Referred fathers","share":"Medium","desc":"Fathers directed by a program or agency who need an objective starting point.","_k":3},{"segment":"Administrators","share":"Enabling","desc":"National Center for Fathering staff who steward content and see aggregate results only.","_k":4}],"persona":[{"persona":"The growth-minded father","needs":"An honest, private read on where he stands, and a small number of concrete next steps he can actually keep.","_k":1},{"persona":"The referred father","needs":"A neutral, non-judgmental starting point that respects his privacy and does not feel like a test he can fail.","_k":2},{"persona":"The group leader","needs":"A simple way for the men in his group to take the baseline, and a way to see participation without seeing anyone’s answers.","_k":3},{"persona":"The content steward","needs":"Confidence that the instrument and its scoring are correct, versioned, and changeable without a code release.","_k":4}],"sol_in":["Capturing informed consent and creating or signing in to a father’s account.","Presenting the assessment items and capturing responses, with pause and resume.","Deterministic scoring: domain scores, overall baseline, strength, and growth focus.","Generating and presenting a ninety-day plan mapped from the growth focus.","Private storage of results and plan, result history, retake, and self-service deletion.","Loading the item bank and scoring model from versioned configuration.","Administrator visibility into aggregate participation and score distributions only."],"sol_out":["Classes, certificates, peer circles, the veterans program, e-signature, and payments. These are later phases and are not specified here.","Any clinical diagnosis, label, or treatment recommendation. The assessment is a developmental baseline, not a clinical instrument.","Coaching by a human, live chat, or case management.","Sharing an individual father’s results with any third party, including a referring organization, without a separate, explicitly specified consent flow.","Non-English localization in Phase 1."],"release":[{"rel":"Phase 1 Baseline Assessment (MVP)","obj":"A father can consent, take the assessment, receive a scored baseline and a ninety-day plan, and manage his own data.","mvp":"to confirm","ship":"to confirm","_k":1},{"rel":"Later phases (context only)","obj":"Classes and the learning library, verifiable certificates, peer circles, and audience-specific programs. Each carries its own requirements document and is out of scope here.","mvp":"to confirm","ship":"to confirm","_k":2}],"components":[],"metrics":[{"metric":"Assessment completion rate","target":"≥ 70% of starters finish (to confirm)","method":"Ratio of completed to started assessments, from lifecycle events.","_k":1},{"metric":"Time to complete","target":"Median ≤ 20 minutes","method":"Elapsed time from first item to completion, from lifecycle events.","_k":2},{"metric":"Scoring correctness","target":"100% agreement with the reference model on golden fixtures","method":"Automated scoring tests against labeled fixtures on every release.","_k":3},{"metric":"Plan generation","target":"100% of completed baselines produce a matched plan","method":"Automated test; monitored rate of completions without a plan, target zero.","_k":4},{"metric":"Privacy incidents","target":"Zero cross-father data exposure","method":"Access-control tests and incident log.","_k":5}],"assume":["The Keystone Father Profile is a validated instrument with an established item bank and scoring model, owned by a psychometric authority who signs off on any change.","Fathers self-report in good faith; the instrument’s design, not enforcement, handles ordinary response bias.","Fathers are adults; the platform does not knowingly collect data from minors.","A father completes the assessment on a single account he controls."],"depend":["Supabase for authentication, the Postgres database, row-level security, and file storage.","Vercel for hosting and delivery of the web application.","A transactional email provider for passwordless sign-in links.","The versioned item bank and scoring model, maintained by the psychometric owner."],"constrain":["Nonprofit budget and a static-site-plus-Supabase architecture; no bespoke server infrastructure in Phase 1.","Consent and privacy obligations for sensitive personal data.","Accessibility to WCAG 2.1 AA.","No clinical diagnosis or claim may be made by the product.","English only in Phase 1."],"fr":[{"stmt":"A father creates an account or signs in before any result is stored.","fit":"An authenticated session exists and each stored result is bound to that account. Test.","pri":"Must","_k":1},{"stmt":"The system records informed consent before it collects any assessment response.","fit":"A consent record with a timestamp exists before the first item is answered; no response is stored without it. Test.","pri":"Must","_k":2},{"stmt":"The system presents the assessment as the set of items defined by the active item-bank version, in the defined order.","fit":"The items presented match the active item-bank version in identity, count, and order. Test.","pri":"Must","_k":3},{"stmt":"Each item captures a response on the item’s defined response scale.","fit":"A response within the defined scale is captured and stored per item; required items cannot be left blank. Test.","pri":"Must","_k":4},{"stmt":"A father can pause and later resume without losing responses.","fit":"On resume, previously captured responses are restored and the father continues from the next unanswered item. Test.","pri":"Must","_k":5},{"stmt":"The system shows progress through the assessment.","fit":"A progress indicator reflects answered items over total items and updates as items are answered. Test.","pri":"Should","_k":6},{"stmt":"The system computes a score for each of the four domains from the item responses per the scoring model.","fit":"For each labeled fixture, the four domain scores equal the reference values. Test.","pri":"Must","_k":7},{"stmt":"Reverse-keyed items are reverse-scored before aggregation.","fit":"For a fixture containing reverse-keyed items, the computed domain scores equal the reference values. Test.","pri":"Must","_k":8},{"stmt":"Each domain score is normalized to a common 0 to 100 scale.","fit":"Every domain score lies within 0 to 100 and equals the reference normalized value for each fixture. Test.","pri":"Must","_k":9},{"stmt":"The system computes a single overall baseline as the defined composite of the domain scores.","fit":"For each fixture, the overall baseline equals the reference composite. Test.","pri":"Must","_k":10},{"stmt":"The system identifies the growth focus as the domain with the largest opportunity per the scoring model.","fit":"For each fixture, the identified growth focus equals the reference selection, including the defined tie-break. Test.","pri":"Must","_k":11},{"stmt":"The system identifies the father’s strongest domain.","fit":"For each fixture, the identified strength equals the reference selection. Test.","pri":"Should","_k":12},{"stmt":"The system generates a ninety-day plan mapped from the growth focus.","fit":"The plan returned for a given growth focus equals the plan configured for that domain. Test.","pri":"Must","_k":13},{"stmt":"The results view presents the four domain scores, the overall baseline, the strength, the growth focus, and the plan.","fit":"Every presented value equals the corresponding stored result value. Inspection and test.","pri":"Must","_k":14},{"stmt":"A father’s result and plan are readable only by that father’s account.","fit":"A request from any other account for the result is denied by row-level security. Test.","pri":"Must","_k":15},{"stmt":"A father can retake the assessment, producing a new result without overwriting a prior one.","fit":"A retake creates a new dated result; prior results remain retrievable. Test.","pri":"Should","_k":16},{"stmt":"Each stored result records the item-bank version and scoring-model version used.","fit":"Every stored result carries both version identifiers. Test.","pri":"Must","_k":17},{"stmt":"The assessment is completable on a mobile browser.","fit":"The full flow, from consent to results, completes on a 375-pixel-wide viewport. Test.","pri":"Must","_k":18},{"stmt":"A father can view his result history.","fit":"Prior results are listed by date and each can be opened. Test.","pri":"Could","_k":19},{"stmt":"A father can delete his assessment data.","fit":"On confirmed request, the father’s responses, results, and plan are removed and the removal is confirmed. Test.","pri":"Must","_k":20},{"stmt":"If a father’s responses meet a defined distress signal (to confirm), the system surfaces support resources without blocking or diagnosing.","fit":"On the defined signal, a non-clinical support resource is shown and the father may continue; no diagnostic language appears. Demonstration and red-team review.","pri":"Should","_k":21},{"stmt":"The item bank and scoring model are loaded from versioned configuration, not embedded in code.","fit":"Publishing a new configuration version changes items or scoring with no code deployment, and the change is recorded. Inspection and test.","pri":"Must","_k":22},{"stmt":"An administrator sees only aggregate participation and score distributions, never an individual father’s answers or scores.","fit":"Administrator views return counts and aggregates; individual raw responses and scores are not returned. Test.","pri":"Must","_k":23},{"stmt":"The system records assessment lifecycle events: started, completed, scored.","fit":"Each event is recorded with a timestamp for the father’s own record and for aggregate metrics. Test.","pri":"Should","_k":24},{"stmt":"On completion the system shows a confirmation and a path to the result.","fit":"A confirmation is shown and the result is reachable from it. Test.","pri":"Must","_k":25},{"stmt":"The product presents no clinical diagnosis, label, or treatment recommendation.","fit":"No output asserts a diagnosis; results and plan language pass a documented content review. Inspection.","pri":"Must","_k":26},{"stmt":"An optional plain-language summary of the result may be generated; if produced by a generative model it is grounded to the father’s computed scores.","fit":"The summary states no score or fact that contradicts the computed result; verified per EVAL-001. Evaluation.","pri":"Should","_k":27}],"nfr":[{"stmt":"The application responds to a user action within 2 seconds at the 95th percentile.","fit":"Measured response time is under 2 seconds at the 95th percentile. Test.","pri":"Must","_k":1},{"stmt":"Scoring is deterministic and reproducible.","fit":"The same responses under the same scoring-model version always produce identical scores. Test.","pri":"Must","_k":2},{"stmt":"Personal data is encrypted in transit and at rest.","fit":"All transport uses TLS; data at rest is encrypted by the platform. Inspection.","pri":"Must","_k":3},{"stmt":"Per-father data isolation is enforced at the database, not only the interface.","fit":"Row-level security denies cross-account reads even on direct database access. Test.","pri":"Must","_k":4},{"stmt":"The assessment and results meet WCAG 2.1 AA.","fit":"An accessibility audit records no Level A or AA violations on the assessment and results flow. Inspection.","pri":"Must","_k":5},{"stmt":"The interface is usable on small screens.","fit":"All controls are operable and legible at a 360-pixel width. Test.","pri":"Must","_k":6},{"stmt":"No response is lost across a pause, refresh, or transient disconnect.","fit":"After each event, all prior responses are present on resume. Test.","pri":"Must","_k":7},{"stmt":"Service availability meets the stated target.","fit":"Monthly availability at or above 99.5% (to confirm), from uptime monitoring.","pri":"Should","_k":8},{"stmt":"The system supports the target concurrent load.","fit":"The assessment completes within performance targets at (to confirm) concurrent fathers. Test.","pri":"Should","_k":9},{"stmt":"The item bank and scoring model are maintainable as data.","fit":"A change to items or scoring is made and released by editing versioned configuration only. Inspection.","pri":"Must","_k":10},{"stmt":"Scoring-model and item-bank changes are auditable.","fit":"Every configuration version records who changed it, when, and what changed. Inspection.","pri":"Must","_k":11},{"stmt":"The application runs on current evergreen browsers.","fit":"The flow passes on the current and prior major versions of the supported browsers. Test.","pri":"Should","_k":12},{"stmt":"Non-English localization.","fit":"N/A for Phase 1. English only.","pri":"Won''t","_k":13}],"eval":[{"dim":"Grounding to the computed result","metric":"Share of generated summaries whose stated scores and facts are numerically consistent with the father’s computed result, on the golden set. Automated numeric-consistency check.","thresh":"100% (zero fabricated or contradictory scores)","_k":1},{"dim":"No clinical or diagnostic claim","metric":"Count of summaries asserting a diagnosis, disorder, or clinical label on a labeled adversarial set. Classifier plus human review.","thresh":"0 violations","_k":2},{"dim":"Safety on distress inputs","metric":"Count of unsafe or harmful outputs on a red-team set of distress-indicating results. Human review.","thresh":"0 unsafe outputs","_k":3},{"dim":"No sycophancy against the data","metric":"Count of summaries that affirm a father’s incorrect self-characterization in contradiction of his scores, on an adversarial set. Human review.","thresh":"0 (to confirm)","_k":4}],"data_entities":[{"entity":"Father accounts","sens":"Personal; identity and sign-in only","_k":1},{"entity":"Assessment responses","sens":"Sensitive personal data; strictest row-level security","_k":2},{"entity":"Domain scores, overall baseline, strength, growth focus","sens":"Sensitive; private to the father","_k":3},{"entity":"Ninety-day plan","sens":"Personal; private to the father","_k":4},{"entity":"Consent records","sens":"Personal; separate, timestamped, before collection","_k":5},{"entity":"Lifecycle events (started, completed, scored)","sens":"Personal for the father; aggregated for metrics","_k":6},{"entity":"Aggregate participation and score distributions","sens":"Aggregate only; the sole administrator view","_k":7}],"interfaces":[{"iface":"Platform identity","req":"Authenticate fathers through the platform identity system (passwordless link or password)","fit":"Authentication succeeds through the identity system. Test.","_k":1},{"iface":"Transactional email","req":"Deliver passwordless sign-in links","fit":"A requested sign-in link is delivered and functions. Test.","_k":2},{"iface":"Platform database","req":"Persist results and responses with row-level security","fit":"Data is written and read only within the father’s access scope. Test.","_k":3},{"iface":"Hosting platform","req":"Deliver the web application from the production host","fit":"The application loads and functions from the production host. Demonstration.","_k":4},{"iface":"Configuration source","req":"Read the active item bank and scoring model at runtime","fit":"The active configuration version is loaded and identified on each result. Inspection.","_k":5},{"iface":"Analytics","req":"Record product and usage lifecycle telemetry (destination to confirm)","fit":"Lifecycle events are recorded to the analytics destination. Test.","_k":6},{"iface":"Generative summary service","req":"If used, integrate behind a server boundary that holds its credentials","fit":"No model credential is present in the browser; the summary is requested through a server function. Inspection.","_k":7}],"people":[{"name":"Micah Canfield","role":"Product owner","_k":1},{"name":"Alon Arad","role":"Engineering","_k":2},{"name":"to confirm","role":"Data and privacy reviewer","_k":3},{"name":"Dr. Ken Canfield","role":"Sponsor, National Center for Fathering","_k":4},{"name":"to confirm","role":"Psychometric owner of the instrument and scoring model","_k":5}],"glossary":[{"term":"Baseline","def":"A father’s scored starting point across the four domains, plus the overall composite.","_k":1},{"term":"Domain","def":"One of the four measured dimensions: Involvement, Consistency, Awareness, Nurturance.","_k":2},{"term":"Growth focus","def":"The domain with the largest opportunity to improve; drives the plan.","_k":3},{"term":"Keystone Father Profile","def":"The validated instrument delivered by the Baseline Father Profile Assessment.","_k":4},{"term":"Fit criterion","def":"The measurable condition that defines acceptance of a requirement.","_k":5},{"term":"Golden dataset","def":"A trusted, labeled set of inputs and expected outcomes used to verify probabilistic components.","_k":6},{"term":"Row-level security","def":"Database rules that restrict each row to its owner, enforced below the interface.","_k":7},{"term":"MoSCoW","def":"Priority scheme: Must, Should, Could, Won’t.","_k":8},{"term":"Item bank","def":"The versioned set of assessment items and their scoring attributes.","_k":9},{"term":"Reverse-keyed item","def":"An item whose scale is inverted before aggregation.","_k":10}],"decisions":[]},"sections":{"control":"# Fathering Baseline Assessment\n\n<meta>National Center for Fathering  ·  Version 1.1  ·  Status Approved  ·  7/7/2026  ·  Owner Micah Canfield</meta>\n\n### Approvals\n\n| Role | Name | Date |\n| --- | --- | --- |\n| Product | Micah Canfield |  |\n| Engineering | Alon Arad |  |\n| Data and Privacy | to confirm |  |\n| Sponsor | Dr. Ken Canfield |  |","overview":"## 1. Overview\n\n### 1.1 Purpose and Audience\n\nThis document specifies the requirements for the Fathers.com Platform. Its first phase delivers the Baseline Father Profile Assessment, the validated self-report instrument that gives a father an objective starting point and a plan. It is the single source of truth for what Phase 1 must do and how acceptance is judged. Its audience is the product owner, the engineering team, the data and privacy reviewer, and the sponsor at the National Center for Fathering, together with the review and traceability process managed in ReqPub. Part I states the product without implementation detail; Part II states the requirements, each with a measurable fit criterion.\n\n### 1.2 Product Vision\n\nFathers.com equips any father to become measurably more present. It replaces vague encouragement with a validated baseline, a clear growth focus, and a personalized ninety-day plan, delivered at no cost by a nonprofit and available on any phone. Over time the platform extends into classes, certificates, peer circles, and programs for specific fathers, but the baseline is the front door: the moment a man learns where he actually stands and what to do next.\n\n### 1.3 Problem Statement\n\nFather absence and disengagement carry well-documented costs to children, and most fathers who want to do better have no objective, non-judgmental way to know where they stand or what specifically to change. Advice is generic, self-assessment is guesswork, and formal instruments are locked inside clinical or academic settings. The Baseline Father Profile Assessment closes that gap by giving any father a private, validated read on four dimensions of engaged fatherhood and a concrete plan built from his own result. It matters now because the instrument exists, the delivery platform is built, and the reach of a nonprofit with established distribution makes scale realistic.\n\n### 1.4 Opportunity and Market\n\nThe addressable population is the tens of millions of fathers of minor children in the United States, reached both directly and through the National Center for Fathering’s existing channels: faith communities, employers, fatherhood programs, and public agencies. The instrument’s value as an objective, court-neutral baseline also opens referral channels where an accountable, verifiable starting point is useful. Phase 1 targets the direct-to-father and partnered-group segments, where friction is lowest and the baseline stands on its own.\n\n### 1.5 Goals and Objectives\n\n- G1. Give a father a valid, private baseline across the four fatherhood domains in a single sitting of about twenty minutes.\n- G2. Translate every baseline into a concrete ninety-day plan mapped to the father’s largest growth opportunity.\n- G3. Protect the father’s data absolutely: private to his account, never sold, his to delete.\n- G4. Deliver the assessment reliably on a phone with no app install and minimal friction.\n- G5. Make scoring reproducible and auditable, so a result can be explained and defended under scrutiny.","users":"## 2. Users and Context\n\n### 2.1 User Segments\n\n| Segment | Share or Priority | Description |\n| --- | --- | --- |\n| Individual fathers | Primary | A father seeking an honest read on his fathering and a plan to improve. |\n| Partnered groups | High | Churches, teams, and fatherhood programs that run the baseline with their men. |\n| Referred fathers | Medium | Fathers directed by a program or agency who need an objective starting point. |\n| Administrators | Enabling | National Center for Fathering staff who steward content and see aggregate results only. |\n\n### 2.2 Personas\n\n| Persona | Needs |\n| --- | --- |\n| The growth-minded father | An honest, private read on where he stands, and a small number of concrete next steps he can actually keep. |\n| The referred father | A neutral, non-judgmental starting point that respects his privacy and does not feel like a test he can fail. |\n| The group leader | A simple way for the men in his group to take the baseline, and a way to see participation without seeing anyone’s answers. |\n| The content steward | Confidence that the instrument and its scoring are correct, versioned, and changeable without a code release. |\n\n### 2.3 Operating Context\n\nThe assessment runs in a web browser on a phone, tablet, or desktop, with no app install. Fathers frequently take it on a personal phone over a mobile connection, in a single sitting or across a short break, so the flow must be responsive, resumable, and tolerant of intermittent connectivity. Because the content is personal and self-reflective, the setting is assumed private to the father, and the platform never exposes one father’s data to another.","solution":"## 3. Solution Overview\n\n### 3.1 The Solution\n\nThe Baseline Father Profile Assessment is the delivery of the Keystone Father Profile: a validated self-report instrument that measures four domains of engaged fatherhood, Involvement, Consistency, Awareness, and Nurturance. A father answers a fixed set of items on a defined response scale. A deterministic scoring engine converts those responses into a score for each domain on a common 0 to 100 scale, a single overall baseline, the father’s strongest domain, and his growth focus, which is the domain with the largest opportunity to improve. From the growth focus the platform generates a ninety-day plan. The result and plan are private to the father. The core of the product is a measurement, not a generative guess: scoring is a fixed function of the responses and a versioned scoring model, so the same responses under the same model always produce the same result, which is what makes a baseline defensible. The model is architected as configuration plus a pure scoring function, kept strictly separate: the item bank, domains, scales, key directions, optional weights, normalization parameters, growth-focus rule, and plan mapping are one versioned configuration object that changes scoring with no code deployment and a full audit record; scoring is a pure function of (responses, model version); and every stored result carries the item-bank and model versions used, so a result computed a year ago can still be explained, recomputed, and defended.\n\n### 3.2 Scope\n\n**In scope**\n\n- Capturing informed consent and creating or signing in to a father’s account.\n- Presenting the assessment items and capturing responses, with pause and resume.\n- Deterministic scoring: domain scores, overall baseline, strength, and growth focus.\n- Generating and presenting a ninety-day plan mapped from the growth focus.\n- Private storage of results and plan, result history, retake, and self-service deletion.\n- Loading the item bank and scoring model from versioned configuration.\n- Administrator visibility into aggregate participation and score distributions only.\n\n**Out of scope**\n\n- Classes, certificates, peer circles, the veterans program, e-signature, and payments. These are later phases and are not specified here.\n- Any clinical diagnosis, label, or treatment recommendation. The assessment is a developmental baseline, not a clinical instrument.\n- Coaching by a human, live chat, or case management.\n- Sharing an individual father’s results with any third party, including a referring organization, without a separate, explicitly specified consent flow.\n- Non-English localization in Phase 1.\n\n### 3.3 Release Plan\n\n| Release | Objective | MVP date | Release date |\n| --- | --- | --- | --- |\n| Phase 1 Baseline Assessment (MVP) | A father can consent, take the assessment, receive a scored baseline and a ninety-day plan, and manage his own data. | to confirm | to confirm |\n| Later phases (context only) | Classes and the learning library, verifiable certificates, peer circles, and audience-specific programs. Each carries its own requirements document and is out of scope here. | to confirm | to confirm |","metrics":"## 4. Success Metrics\n\n| Metric | Target | Measurement Method |\n| --- | --- | --- |\n| Assessment completion rate | ≥ 70% of starters finish (to confirm) | Ratio of completed to started assessments, from lifecycle events. |\n| Time to complete | Median ≤ 20 minutes | Elapsed time from first item to completion, from lifecycle events. |\n| Scoring correctness | 100% agreement with the reference model on golden fixtures | Automated scoring tests against labeled fixtures on every release. |\n| Plan generation | 100% of completed baselines produce a matched plan | Automated test; monitored rate of completions without a plan, target zero. |\n| Privacy incidents | Zero cross-father data exposure | Access-control tests and incident log. |","method":"## 5. Requirements Method and Conventions\n\n**Identifiers.** FR for functional, NFR for non-functional, EVAL for an AI evaluation criterion, DR for data and privacy, IR for interface. Identifiers are permanent and are not reused.\n\n**Fit criterion.** Every requirement carries a measurable fit criterion that defines acceptance. A requirement with no fit criterion is not finished.\n\n**Priority.** MoSCoW: Must, Should, Could, or Won''t for the stated release.\n\n**Verification.** Deterministic requirements are verified by test, inspection, or demonstration. Probabilistic or AI components are verified by evaluation against a golden dataset with a stated threshold, because the same input can produce different outputs and correctness is a distribution rather than a single value. Safety requirements are verified on a red-team set with human review.\n\n**Open items.** A value marked [to confirm] is a proposed default awaiting stakeholder confirmation.","adc":"## 6. Assumptions, Dependencies, and Constraints\n\n### 6.1 Assumptions\n\n- The Keystone Father Profile is a validated instrument with an established item bank and scoring model, owned by a psychometric authority who signs off on any change.\n- Fathers self-report in good faith; the instrument’s design, not enforcement, handles ordinary response bias.\n- Fathers are adults; the platform does not knowingly collect data from minors.\n- A father completes the assessment on a single account he controls.\n\n### 6.2 Dependencies\n\n- Supabase for authentication, the Postgres database, row-level security, and file storage.\n- Vercel for hosting and delivery of the web application.\n- A transactional email provider for passwordless sign-in links.\n- The versioned item bank and scoring model, maintained by the psychometric owner.\n\n### 6.3 Constraints\n\n- Nonprofit budget and a static-site-plus-Supabase architecture; no bespoke server infrastructure in Phase 1.\n- Consent and privacy obligations for sensitive personal data.\n- Accessibility to WCAG 2.1 AA.\n- No clinical diagnosis or claim may be made by the product.\n- English only in Phase 1.","functional":"## 7. Functional Requirements\n\n| ID | Requirement | Fit Criterion and Acceptance | Priority |\n| --- | --- | --- | --- |\n| FR-001 | A father creates an account or signs in before any result is stored. | An authenticated session exists and each stored result is bound to that account. Test. | Must |\n| FR-002 | The system records informed consent before it collects any assessment response. | A consent record with a timestamp exists before the first item is answered; no response is stored without it. Test. | Must |\n| FR-003 | The system presents the assessment as the set of items defined by the active item-bank version, in the defined order. | The items presented match the active item-bank version in identity, count, and order. Test. | Must |\n| FR-004 | Each item captures a response on the item’s defined response scale. | A response within the defined scale is captured and stored per item; required items cannot be left blank. Test. | Must |\n| FR-005 | A father can pause and later resume without losing responses. | On resume, previously captured responses are restored and the father continues from the next unanswered item. Test. | Must |\n| FR-006 | The system shows progress through the assessment. | A progress indicator reflects answered items over total items and updates as items are answered. Test. | Should |\n| FR-007 | The system computes a score for each of the four domains from the item responses per the scoring model. | For each labeled fixture, the four domain scores equal the reference values. Test. | Must |\n| FR-008 | Reverse-keyed items are reverse-scored before aggregation. | For a fixture containing reverse-keyed items, the computed domain scores equal the reference values. Test. | Must |\n| FR-009 | Each domain score is normalized to a common 0 to 100 scale. | Every domain score lies within 0 to 100 and equals the reference normalized value for each fixture. Test. | Must |\n| FR-010 | The system computes a single overall baseline as the defined composite of the domain scores. | For each fixture, the overall baseline equals the reference composite. Test. | Must |\n| FR-011 | The system identifies the growth focus as the domain with the largest opportunity per the scoring model. | For each fixture, the identified growth focus equals the reference selection, including the defined tie-break. Test. | Must |\n| FR-012 | The system identifies the father’s strongest domain. | For each fixture, the identified strength equals the reference selection. Test. | Should |\n| FR-013 | The system generates a ninety-day plan mapped from the growth focus. | The plan returned for a given growth focus equals the plan configured for that domain. Test. | Must |\n| FR-014 | The results view presents the four domain scores, the overall baseline, the strength, the growth focus, and the plan. | Every presented value equals the corresponding stored result value. Inspection and test. | Must |\n| FR-015 | A father’s result and plan are readable only by that father’s account. | A request from any other account for the result is denied by row-level security. Test. | Must |\n| FR-016 | A father can retake the assessment, producing a new result without overwriting a prior one. | A retake creates a new dated result; prior results remain retrievable. Test. | Should |\n| FR-017 | Each stored result records the item-bank version and scoring-model version used. | Every stored result carries both version identifiers. Test. | Must |\n| FR-018 | The assessment is completable on a mobile browser. | The full flow, from consent to results, completes on a 375-pixel-wide viewport. Test. | Must |\n| FR-019 | A father can view his result history. | Prior results are listed by date and each can be opened. Test. | Could |\n| FR-020 | A father can delete his assessment data. | On confirmed request, the father’s responses, results, and plan are removed and the removal is confirmed. Test. | Must |\n| FR-021 | If a father’s responses meet a defined distress signal (to confirm), the system surfaces support resources without blocking or diagnosing. | On the defined signal, a non-clinical support resource is shown and the father may continue; no diagnostic language appears. Demonstration and red-team review. | Should |\n| FR-022 | The item bank and scoring model are loaded from versioned configuration, not embedded in code. | Publishing a new configuration version changes items or scoring with no code deployment, and the change is recorded. Inspection and test. | Must |\n| FR-023 | An administrator sees only aggregate participation and score distributions, never an individual father’s answers or scores. | Administrator views return counts and aggregates; individual raw responses and scores are not returned. Test. | Must |\n| FR-024 | The system records assessment lifecycle events: started, completed, scored. | Each event is recorded with a timestamp for the father’s own record and for aggregate metrics. Test. | Should |\n| FR-025 | On completion the system shows a confirmation and a path to the result. | A confirmation is shown and the result is reachable from it. Test. | Must |\n| FR-026 | The product presents no clinical diagnosis, label, or treatment recommendation. | No output asserts a diagnosis; results and plan language pass a documented content review. Inspection. | Must |\n| FR-027 | An optional plain-language summary of the result may be generated; if produced by a generative model it is grounded to the father’s computed scores. | The summary states no score or fact that contradicts the computed result; verified per EVAL-001. Evaluation. | Should |","nonfunctional":"## 8. Non-Functional Requirements\n\n| ID | Requirement | Fit Criterion and Acceptance | Priority |\n| --- | --- | --- | --- |\n| NFR-001 | The application responds to a user action within 2 seconds at the 95th percentile. | Measured response time is under 2 seconds at the 95th percentile. Test. | Must |\n| NFR-002 | Scoring is deterministic and reproducible. | The same responses under the same scoring-model version always produce identical scores. Test. | Must |\n| NFR-003 | Personal data is encrypted in transit and at rest. | All transport uses TLS; data at rest is encrypted by the platform. Inspection. | Must |\n| NFR-004 | Per-father data isolation is enforced at the database, not only the interface. | Row-level security denies cross-account reads even on direct database access. Test. | Must |\n| NFR-005 | The assessment and results meet WCAG 2.1 AA. | An accessibility audit records no Level A or AA violations on the assessment and results flow. Inspection. | Must |\n| NFR-006 | The interface is usable on small screens. | All controls are operable and legible at a 360-pixel width. Test. | Must |\n| NFR-007 | No response is lost across a pause, refresh, or transient disconnect. | After each event, all prior responses are present on resume. Test. | Must |\n| NFR-008 | Service availability meets the stated target. | Monthly availability at or above 99.5% (to confirm), from uptime monitoring. | Should |\n| NFR-009 | The system supports the target concurrent load. | The assessment completes within performance targets at (to confirm) concurrent fathers. Test. | Should |\n| NFR-010 | The item bank and scoring model are maintainable as data. | A change to items or scoring is made and released by editing versioned configuration only. Inspection. | Must |\n| NFR-011 | Scoring-model and item-bank changes are auditable. | Every configuration version records who changed it, when, and what changed. Inspection. | Must |\n| NFR-012 | The application runs on current evergreen browsers. | The flow passes on the current and prior major versions of the supported browsers. Test. | Should |\n| NFR-013 | Non-English localization. | N/A for Phase 1. English only. | Won''t |","aieval":"## 9. AI Evaluation Criteria\n\n| ID | Quality Dimension | Metric and Method | Threshold |\n| --- | --- | --- | --- |\n| EVAL-001 | Grounding to the computed result | Share of generated summaries whose stated scores and facts are numerically consistent with the father’s computed result, on the golden set. Automated numeric-consistency check. | 100% (zero fabricated or contradictory scores) |\n| EVAL-002 | No clinical or diagnostic claim | Count of summaries asserting a diagnosis, disorder, or clinical label on a labeled adversarial set. Classifier plus human review. | 0 violations |\n| EVAL-003 | Safety on distress inputs | Count of unsafe or harmful outputs on a red-team set of distress-indicating results. Human review. | 0 unsafe outputs |\n| EVAL-004 | No sycophancy against the data | Count of summaries that affirm a father’s incorrect self-characterization in contradiction of his scores, on an adversarial set. Human review. | 0 (to confirm) |\n\n**Golden dataset and red-team method.** The golden dataset pairs computed results with the facts a correct summary must and must not state, curated from vetted sources. An automated harness runs each candidate build against it and reports grounding, accuracy, latency, and guardrail metrics; a build below any EVAL threshold does not ship. A red-team set probes for hallucination, unsafe handling of distress, and sycophancy, with human review before and after release. This method applies to any release that introduces a generative result summary (FR-027); Phase 1 scoring itself is deterministic and verified by test against labeled fixtures, not by evaluation.","data":"## 10. Data, Privacy, and Safeguarding\n\n| ID | Requirement | Fit Criterion and Acceptance | Priority |\n| --- | --- | --- | --- |\n| DR-001 | The platform identifies and records the data entities it holds: Father accounts (Personal; identity and sign-in only); Assessment responses (Sensitive personal data; strictest row-level security); Domain scores, overall baseline, strength, growth focus (Sensitive; private to the father); Ninety-day plan (Personal; private to the father); Consent records (Personal; separate, timestamped, before collection); Lifecycle events (started, completed, scored) (Personal for the father; aggregated for metrics); Aggregate participation and score distributions (Aggregate only; the sole administrator view) | A data inventory lists each entity, its owner, and its sensitivity. Inspection. | Must |\n| DR-002 | Sensitive entities are classified and protected accordingly | Each sensitive entity carries a sensitivity classification and the matching controls. Inspection. | Must |\n| DR-003 | The platform obtains and records informed consent, with a timestamp, before it collects any assessment response; no response is stored without it. Individual results are never sold or shared with any third party; sharing an individual result to a referring organization requires a separate, explicitly specified consent flow that is out of scope for Phase 1. | Consent is captured and stored before collection begins. Test. | Must |\n| DR-004 | A father can delete his assessment data at any time; on confirmed request his responses, results, and plan are removed and the removal is confirmed. Retention beyond deletion follows a stated policy (to confirm). A father can retake the assessment, producing a new dated result without overwriting prior ones, and can view his result history. | A retention schedule exists per entity, and export and deletion requests are fulfilled. Test. | Must |\n| DR-005 | Assessment data is classified and handled as sensitive personal data. Personal data is encrypted in transit (TLS) and at rest. Data is stored in the region defined by the residency requirement (to confirm). | A documented data residency position exists and the deployment conforms to it. Inspection. | Must |\n| DR-006 | A father’s responses, scores, and plan are private to his account and readable only by it; per-father isolation is enforced by row-level security at the database, not only the interface, so cross-account reads are denied even on direct database access. Administrators see only aggregate participation and score distributions, never an individual father’s answers or scores; any authorized access to individual data is logged. The platform does not knowingly process the data of minors. | Access controls restrict data to authorized roles and access is logged. Test. | Must |\n| DR-007 | If a father’s responses meet a defined distress signal (to confirm), the system surfaces a non-clinical support resource without blocking the father and without diagnosing; no diagnostic language appears. The response is verified by demonstration and red-team review, and reviewed by a clinical or policy owner. The product makes no clinical diagnosis, label, or treatment recommendation anywhere. | A defined safeguarding response exists and is triggered by the agreed indicators. Review and test. Requires clinical and policy sign-off. | Must |","interfaces":"## 11. Interfaces and Integrations\n\n| ID | Requirement | Fit Criterion and Acceptance | Priority |\n| --- | --- | --- | --- |\n| IR-001 | Platform identity. Authenticate fathers through the platform identity system (passwordless link or password) | Authentication succeeds through the identity system. Test. | Must |\n| IR-002 | Transactional email. Deliver passwordless sign-in links | A requested sign-in link is delivered and functions. Test. | Must |\n| IR-003 | Platform database. Persist results and responses with row-level security | Data is written and read only within the father’s access scope. Test. | Must |\n| IR-004 | Hosting platform. Deliver the web application from the production host | The application loads and functions from the production host. Demonstration. | Must |\n| IR-005 | Configuration source. Read the active item bank and scoring model at runtime | The active configuration version is loaded and identified on each result. Inspection. | Must |\n| IR-006 | Analytics. Record product and usage lifecycle telemetry (destination to confirm) | Lifecycle events are recorded to the analytics destination. Test. | Must |\n| IR-007 | Generative summary service. If used, integrate behind a server boundary that holds its credentials | No model credential is present in the browser; the summary is requested through a server function. Inspection. | Must |","verification":"## 12. Verification and Acceptance\n\nEvery requirement in this document carries a fit criterion. Deterministic requirements are verified by test, inspection, or demonstration. Probabilistic or AI components are verified by evaluation against a golden dataset with the stated threshold. Safety requirements are verified on a red-team or scenario set with human review. A release is accepted when every Must requirement for that release passes its fit criterion and every evaluation criterion meets its threshold.\n\nEvery requirement carries a fit criterion. Deterministic requirements are verified by test, inspection, or demonstration. Probabilistic or AI components are verified by evaluation against a golden dataset with the stated threshold. Safety requirements are verified on a red-team or scenario set with human review. Phase 1 is accepted when every Must requirement passes its fit criterion and every applicable evaluation criterion meets its threshold.","traceability":"## 13. Traceability\n\nThe matrix links each goal to the requirements that serve it and to the metric that verifies it. It is maintained as requirements change.\n\n| Goal | Supporting Requirements | Verification or KPI |\n| --- | --- | --- |\n| G1. Give a father a valid, private baseline across the four fatherhood domains in a single sitting of about twenty minutes. | See Sections 7 to 11 | Assessment completion rate; Time to complete |\n| G2. Translate every baseline into a concrete ninety-day plan mapped to the father’s largest growth opportunity. | See Sections 7 to 11 | Assessment completion rate; Time to complete |\n| G3. Protect the father’s data absolutely: private to his account, never sold, his to delete. | See Sections 7 to 11 | Assessment completion rate; Time to complete |\n| G4. Deliver the assessment reliably on a phone with no app install and minimal friction. | See Sections 7 to 11 | Assessment completion rate; Time to complete |\n| G5. Make scoring reproducible and auditable, so a result can be explained and defended under scrutiny. | See Sections 7 to 11 | Assessment completion rate; Time to complete |","people":"## 14. People, Roles, and Links\n\n### 14.1 People and Roles\n\n| Name | Role |\n| --- | --- |\n| Micah Canfield | Product owner |\n| Alon Arad | Engineering |\n| to confirm | Data and privacy reviewer |\n| Dr. Ken Canfield | Sponsor, National Center for Fathering |\n| to confirm | Psychometric owner of the instrument and scoring model |\n\n### 14.2 Collaboration Links\n\n- Repository: to confirm\n- Project board: to confirm\n- Design: FORGE design system, on the production platform","glossary":"## 15. Glossary\n\n| Term | Definition |\n| --- | --- |\n| Baseline | A father’s scored starting point across the four domains, plus the overall composite. |\n| Domain | One of the four measured dimensions: Involvement, Consistency, Awareness, Nurturance. |\n| Growth focus | The domain with the largest opportunity to improve; drives the plan. |\n| Keystone Father Profile | The validated instrument delivered by the Baseline Father Profile Assessment. |\n| Fit criterion | The measurable condition that defines acceptance of a requirement. |\n| Golden dataset | A trusted, labeled set of inputs and expected outcomes used to verify probabilistic components. |\n| Row-level security | Database rules that restrict each row to its owner, enforced below the interface. |\n| MoSCoW | Priority scheme: Must, Should, Could, Won’t. |\n| Item bank | The versioned set of assessment items and their scoring attributes. |\n| Reverse-keyed item | An item whose scale is inverted before aggregation. |","decisions":"## 16. Decisions and Rationale\n\n_No decisions recorded yet._","revision":"## 17. Revision History\n\n| Version | Date | Author | Description |\n| --- | --- | --- | --- |\n| 1.1 | 7/6/2026 | Micah Canfield | Baseline Father Profile Assessment, Phase 1 (FC-REQ-001). |"}}'::jsonb, (select owner from _fb), now();

-- Record the document's named approvers as signed off. The provenance trigger
-- forces new rows to 'pending', so we insert then mark approved (attributed to
-- the workspace owner).
insert into version_approvals (version_id, approver_role, approver_name)
select v.id, a.role, a.name
from (select id from versions where project_id = (select pid from _fb) and label = '1.1') v,
     (values ('Product', 'Micah Canfield'),
             ('Engineering', 'Alon Arad'),
             ('Sponsor', 'Dr. Ken Canfield')) as a(role, name);

update version_approvals set status = 'approved', decided_by = (select owner from _fb), decided_at = now()
where version_id in (select id from versions where project_id = (select pid from _fb) and label = '1.1');

commit;

